import "../styles/Home.css";

function Home() {
  return (
    <div className="home-container">
      <div className="home-poster-section">
        <img 
          src="/roko.png" 
          alt="Roko Team Poster" 
          className="home-poster"
          onError={(e) => {
            e.target.style.display = "none";
          }}
        />
      </div>

      <div className="home-content">
        <h2>🏏 Welcome to Cricket Stats App</h2>
        <p>
          This application provides live cricket scores, match details,
          and player performance statistics.
        </p>
      </div>

      <div className="home-poster-section">
        <img 
          src="/aussies.png" 
          alt="Aussies Team Poster" 
          className="home-poster"
          onError={(e) => {
            e.target.style.display = "none";
          }}
        />
      </div>
    </div>
  );
}

export default Home;
